	"container/heap"
	"math"
)

type MinHeap [][2]int64

func (h MinHeap) Len() int           { return len(h) }
func (h MinHeap) Less(i, j int) bool { return h[i][0] < h[j][0] }
func (h MinHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }
func (h *MinHeap) Push(x interface{}) {
	*h = append(*h, x.([2]int64))
}
func (h *MinHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[0 : n-1]
	return x
}

func solve(n int64, edges [][]int64) int64 {
	nInt := int(n)
	graph := make([][][3]int64, nInt)
	for i := range edges {
		u := edges[i][0]
		v := edges[i][1]
		s := edges[i][2]
		e := edges[i][3]
		uIdx := int(u)
		graph[uIdx] = append(graph[uIdx], [3]int64{v, s, e})
	}

	dist := make([]int64, nInt)
	for i := range dist {
		dist[i] = math.MaxInt64
	}
	dist[0] = 0

	if nInt == 1 {
		return 0
	}

	pq := &MinHeap{}
	heap.Init(pq)
	heap.Push(pq, [2]int64{0, 0})

	for pq.Len() > 0 {
		item := heap.Pop(pq).([2]int64)
		t := item[0]
		u := item[1]
		uIdx := int(u)
		if t != dist[uIdx] {
			continue
		}
		if u == n-1 {
			return t
		}
		for _, edge := range graph[uIdx] {
			v := edge[0]
			s := edge[1]
			e := edge[2]
			if t > e {
				continue
			}
			startTime := s
			if t > s {
				startTime = t
			}
			candidate := startTime + 1
			vIdx := int(v)
			if candidate < dist[vIdx] {
				dist[vIdx] = candidate
				heap.Push(pq, [2]int64{candidate, v})
			}
		}
	}

	if dist[nInt-1] == math.MaxInt64 {
		return -1
	}
	return dist[nInt-1]
}
