        graph[u] = append(graph[u], [3]int64{v, s, e})
    }

    pq := make(PriorityQueue, 0)
    heap.Push(&pq, NodeTime{time: 0, node: 0})

    for pq.Len() > 0 {
        item := heap.Pop(&pq).(NodeTime)
        t, u := item.time, item.node
        if t != dist[u] {
            continue
